<script setup lang="ts">import { onMounted,reactive,ref } from 'vue';import { ElMessage,ElMessageBox,FormInstance } from 'element-plus';import { http,messageOf } from '@/api/http'; interface User{id:string;username:string;enabled:boolean;createdAt:string} const items=ref<User[]>([]),loading=ref(false),dialog=ref(false),editing=ref<User>(),form=reactive({username:'',password:'',enabled:true});async function load(){loading.value=true;try{items.value=(await http.get('/users')).data}catch(e){ElMessage.error(messageOf(e))}finally{loading.value=false}}function open(user?:User){editing.value=user;form.username=user?.username||'';form.password='';form.enabled=user?.enabled??true;dialog.value=true}async function save(){try{if(editing.value)await http.patch(`/users/${editing.value.id}`,{username:form.username,enabled:form.enabled,...(form.password?{password:form.password}:{})});else await http.post('/users',{username:form.username,password:form.password});ElMessage.success('已保存');dialog.value=false;load()}catch(e){ElMessage.error(messageOf(e))}}async function remove(u:User){try{await ElMessageBox.confirm(`删除账号“${u.username}”？存在关联数据时将改为停用。`,'删除账号',{type:'warning'});await http.delete(`/users/${u.id}`);ElMessage.success('已处理');load()}catch{}}onMounted(load)</script>
<template><div class="page"><div class="toolbar"><span class="grow"></span><el-button type="primary" @click="open()">新增账号</el-button></div><el-table v-loading="loading" :data="items"><el-table-column prop="username" label="用户名" min-width="160"/><el-table-column label="状态" width="100"><template #default="{row}"><el-tag :type="row.enabled?'success':'info'" effect="plain">{{row.enabled?'正常':'已停用'}}</el-tag></template></el-table-column><el-table-column label="创建时间" width="180" class-name="desktop-only"><template #default="{row}">{{new Date(row.createdAt).toLocaleString('zh-CN',{hour12:false})}}</template></el-table-column><el-table-column label="操作" width="150"><template #default="{row}"><el-button link type="primary" @click="open(row)">编辑</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="dialog" :title="editing?'编辑账号':'新增账号'" width="min(430px,92vw)"><el-form label-position="top"><el-form-item label="用户名" required><el-input v-model="form.username" maxlength="50"/></el-form-item><el-form-item :label="editing?'新密码（留空不修改）':'密码'" :required="!editing"><el-input v-model="form.password" type="password" show-password minlength="8"/></el-form-item><el-form-item v-if="editing" label="状态"><el-switch v-model="form.enabled" active-text="启用"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :disabled="!form.username||(!editing&&!form.password)||!!form.password&&form.password.length<8" @click="save">保存</el-button></template></el-dialog></div></template>
